import React, { useEffect, useMemo, useState } from 'react';
import axios from 'axios';
import { toast } from 'react-toastify';

const StockManagement = () => {
  const [loading, setLoading] = useState(true);
  const [stocks, setStocks] = useState([]);
  const [types, setTypes] = useState([]); // [{_id, name}]
  const [typeFilter, setTypeFilter] = useState('ALL'); // 'ALL' or typeId
  const [typesLoading, setTypesLoading] = useState(false);
  const [newTypeName, setNewTypeName] = useState('');
  const [creating, setCreating] = useState(false);
  const [newItem, setNewItem] = useState({ name: '', quantity: 0, maxQuantity: 0, typeId: '' });

  const loadStocks = async () => {
    try {
      setLoading(true);
      const res = await axios.get('/api/stocks');
      setStocks(res.data.stocks || []);
    } catch (error) {
      console.error('Load stocks error:', error);
      toast.error('Failed to load stocks');
    } finally {
      setLoading(false);
    }
  };

  const loadTypes = async () => {
    try {
      setTypesLoading(true);
      const res = await axios.get('/api/stock-types');
      setTypes(res.data.types || []);
    } catch (error) {
      console.error('Load stock types error:', error);
      toast.error('Failed to load stock types');
    } finally {
      setTypesLoading(false);
    }
  };

  useEffect(() => {
    loadTypes();
    loadStocks();
  }, []);

  useEffect(() => {
    // Default new item type to OTHER if present.
    if (!newItem.typeId && Array.isArray(types) && types.length > 0) {
      const other = types.find(t => (t.name || '').toUpperCase() === 'OTHER');
      if (other?._id) setNewItem(prev => ({ ...prev, typeId: other._id }));
    }
  }, [types, newItem.typeId]);

  const sortedStocks = useMemo(() => {
    const list = [...stocks].sort((a, b) => (a.nameNormalized || '').localeCompare(b.nameNormalized || ''));
    if (typeFilter === 'ALL') return list;
    return list.filter(s => (s.typeId?._id || '') === typeFilter);
  }, [stocks, typeFilter]);

  const handleInlineUpdate = async (id, patch) => {
    try {
      const res = await axios.put(`/api/stocks/${id}`, patch);
      setStocks(prev => prev.map(s => (s._id === id ? res.data.stock : s)));
      toast.success('Stock updated');
    } catch (error) {
      console.error('Update stock error:', error);
      const message = error.response?.data?.message || 'Failed to update stock';
      toast.error(message);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    try {
      setCreating(true);
      const res = await axios.post('/api/stocks', {
        name: newItem.name,
        quantity: Number(newItem.quantity || 0),
        maxQuantity: Number(newItem.maxQuantity || 0),
        typeId: newItem.typeId || undefined
      });
      setStocks(prev => [...prev, res.data.stock]);
      setNewItem(prev => ({ ...prev, name: '', quantity: 0, maxQuantity: 0 }));
      toast.success('Stock item added');
    } catch (error) {
      console.error('Create stock error:', error);
      const message = error.response?.data?.message || 'Failed to add stock item';
      toast.error(message);
    } finally {
      setCreating(false);
    }
  };

  const handleCreateType = async (e) => {
    e.preventDefault();
    const name = (newTypeName || '').trim();
    if (!name) return;

    try {
      const res = await axios.post('/api/stock-types', { name });
      setTypes(prev => [...prev, res.data.type]);
      setNewTypeName('');
      toast.success('Type created');
    } catch (error) {
      console.error('Create type error:', error);
      const message = error.response?.data?.message || 'Failed to create type';
      toast.error(message);
    }
  };

  const handleRenameType = async (type) => {
    const nextName = window.prompt('Rename type:', type?.name || '');
    if (nextName === null) return;
    const name = (nextName || '').trim();
    if (!name) return;

    try {
      const res = await axios.put(`/api/stock-types/${type._id}`, { name });
      setTypes(prev => prev.map(t => (t._id === type._id ? res.data.type : t)));
      // Also refresh stocks because server syncs legacy label
      loadStocks();
      toast.success('Type updated');
    } catch (error) {
      console.error('Rename type error:', error);
      const message = error.response?.data?.message || 'Failed to update type';
      toast.error(message);
    }
  };

  const handleDeleteType = async (type) => {
    if (!window.confirm(`Delete type "${type?.name}"?`)) return;
    try {
      await axios.delete(`/api/stock-types/${type._id}`);
      setTypes(prev => prev.filter(t => t._id !== type._id));
      // If current filter deleted, reset.
      if (typeFilter === type._id) setTypeFilter('ALL');
      toast.success('Type deleted');
    } catch (error) {
      console.error('Delete type error:', error);
      const message = error.response?.data?.message || 'Failed to delete type';
      toast.error(message);
    }
  };

  const handleDeleteStock = async (id) => {
    if (!window.confirm('Delete this stock item?')) return;
    try {
      await axios.delete(`/api/stocks/${id}`);
      setStocks(prev => prev.filter(s => s._id !== id));
      toast.success('Stock item deleted');
    } catch (error) {
      console.error('Delete stock error:', error);
      const message = error.response?.data?.message || 'Failed to delete stock item';
      toast.error(message);
    }
  };

  if (loading) {
    return (
      <div className="fade-in">
        <div className="d-flex justify-content-center align-items-center" style={{ minHeight: '300px' }}>
          <div className="spinner-border text-primary" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="fade-in">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
          <h1 className="h2 mb-0">Stocks</h1>
          <p className="text-muted mb-0">Manage stock quantity and capacity (max quantity)</p>
        </div>
        <button className="btn btn-outline-primary" onClick={loadStocks}>
          <i className="fas fa-sync me-2"></i>
          Refresh
        </button>
      </div>

      <div className="card mb-4">
        <div className="card-header d-flex justify-content-between align-items-center">
          <h5 className="mb-0">Stock Types</h5>
          <button className="btn btn-sm btn-outline-secondary" onClick={loadTypes} disabled={typesLoading}>
            <i className="fas fa-sync me-2"></i>
            {typesLoading ? 'Loading...' : 'Refresh'}
          </button>
        </div>
        <div className="card-body">
          <form onSubmit={handleCreateType} className="row g-2 align-items-end mb-3">
            <div className="col-md-6">
              <label className="form-label">New Type</label>
              <input
                className="form-control"
                value={newTypeName}
                onChange={(e) => setNewTypeName(e.target.value)}
                placeholder="e.g. ELECTRONICS"
              />
            </div>
            <div className="col-md-3">
              <button className="btn btn-primary w-100" type="submit" disabled={!newTypeName.trim()}>
                Add Type
              </button>
            </div>
          </form>

          {types.length === 0 ? (
            <div className="text-muted">No types</div>
          ) : (
            <div className="table-responsive">
              <table className="table table-hover align-middle mb-0">
                <thead>
                  <tr>
                    <th>Name</th>
                    <th style={{ width: '220px' }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {types.map(t => (
                    <tr key={t._id}>
                      <td className="fw-semibold">{t.name}</td>
                      <td>
                        <div className="d-flex gap-2">
                          <button className="btn btn-sm btn-outline-primary" onClick={() => handleRenameType(t)} type="button">
                            Rename
                          </button>
                          <button className="btn btn-sm btn-outline-danger" onClick={() => handleDeleteType(t)} type="button">
                            Delete
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
          <div className="small text-muted mt-2">
            Note: A type cannot be deleted if it is used by any stock item.
          </div>
        </div>
      </div>

      <div className="card mb-4">
        <div className="card-header">
          <h5 className="mb-0">Add Stock Item</h5>
        </div>
        <div className="card-body">
          <form onSubmit={handleCreate}>
            <div className="row g-3 align-items-end">
              <div className="col-md-3">
                <label className="form-label">Type</label>
                <select
                  className="form-select"
                  value={newItem.typeId}
                  onChange={(e) => setNewItem(prev => ({ ...prev, typeId: e.target.value }))}
                >
                  {types.map(t => (
                    <option key={t._id} value={t._id}>{t.name}</option>
                  ))}
                </select>
              </div>
              <div className="col-md-5">
                <label className="form-label">Name</label>
                <input
                  className="form-control"
                  value={newItem.name}
                  onChange={(e) => setNewItem(prev => ({ ...prev, name: e.target.value }))}
                  placeholder="e.g. Printer Cartridge"
                  required
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Quantity</label>
                <input
                  type="number"
                  min="0"
                  className="form-control"
                  value={newItem.quantity}
                  onChange={(e) => setNewItem(prev => ({ ...prev, quantity: e.target.value }))}
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Max Quantity</label>
                <input
                  type="number"
                  min="0"
                  className="form-control"
                  value={newItem.maxQuantity}
                  onChange={(e) => setNewItem(prev => ({ ...prev, maxQuantity: e.target.value }))}
                />
              </div>
              <div className="col-12">
                <button className="btn btn-primary" type="submit" disabled={creating}>
                  {creating ? 'Adding...' : 'Add'}
                </button>
              </div>
            </div>
          </form>
          <div className="small text-muted mt-2">
            Note: If max quantity is 0, it is treated as unlimited.
          </div>
        </div>
      </div>

      <div className="card">
        <div className="card-header d-flex justify-content-between align-items-center">
          <h5 className="mb-0">Stock List</h5>
          <div className="d-flex align-items-center gap-2">
            <select
              className="form-select form-select-sm"
              style={{ width: '200px' }}
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
            >
              <option value="ALL">All Types</option>
              {types.map(t => (
                <option key={t._id} value={t._id}>{t.name}</option>
              ))}
            </select>
            <span className="text-muted small">{sortedStocks.length} items</span>
          </div>
        </div>
        <div className="card-body">
          {sortedStocks.length === 0 ? (
            <div className="text-center text-muted py-4">No stock items</div>
          ) : (
            <div className="table-responsive">
              <table className="table table-hover align-middle">
                <thead>
                  <tr>
                    <th style={{ width: '180px' }}>Type</th>
                    <th>Name</th>
                    <th style={{ width: '160px' }}>Quantity</th>
                    <th style={{ width: '180px' }}>Max Quantity</th>
                    <th style={{ width: '140px' }}>Status</th>
                    <th style={{ width: '220px' }}>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {sortedStocks.map(item => {
                    const isLimited = Number(item.maxQuantity || 0) > 0;
                    const isFull = isLimited && Number(item.quantity || 0) >= Number(item.maxQuantity || 0);
                    const isBlocked = item.status === 'BLOCKED';
                    return (
                      <tr key={item._id}>
                        <td>
                          <select
                            className="form-select form-select-sm"
                            value={item.typeId?._id || ''}
                            onChange={(e) => handleInlineUpdate(item._id, { typeId: e.target.value })}
                          >
                            <option value="">OTHER</option>
                            {types.map(t => (
                              <option key={t._id} value={t._id}>{t.name}</option>
                            ))}
                          </select>
                        </td>
                        <td className="fw-semibold">{item.name}</td>
                        <td>{item.quantity}</td>
                        <td>{item.maxQuantity || 0}</td>
                        <td>
                          {isBlocked ? (
                            <span className="badge bg-secondary">BLOCKED</span>
                          ) : (
                            <span className={`badge ${isFull ? 'bg-danger' : 'bg-success'}`}>
                              {isFull ? 'FULL' : 'ACTIVE'}
                            </span>
                          )}
                        </td>
                        <td>
                          <div className="d-flex gap-2">
                            <button
                              className="btn btn-sm btn-outline-secondary"
                              onClick={() => handleInlineUpdate(item._id, { quantity: Math.max(0, Number(item.quantity || 0) - 1) })}
                              disabled={Number(item.quantity || 0) <= 0}
                              title="Decrease quantity"
                            >
                              -1
                            </button>
                            <button
                              className="btn btn-sm btn-outline-secondary"
                              onClick={() => handleInlineUpdate(item._id, { quantity: Number(item.quantity || 0) + 1 })}
                              title="Increase quantity"
                            >
                              +1
                            </button>
                            <button
                              className="btn btn-sm btn-outline-primary"
                              onClick={() => {
                                const max = window.prompt('Set max quantity (0 = unlimited):', String(item.maxQuantity || 0));
                                if (max === null) return;
                                handleInlineUpdate(item._id, { maxQuantity: Number(max) });
                              }}
                              title="Set max quantity"
                            >
                              Set Max
                            </button>
                            <button
                              className={`btn btn-sm ${isBlocked ? 'btn-success' : 'btn-outline-danger'}`}
                              onClick={() => handleInlineUpdate(item._id, { status: isBlocked ? 'ACTIVE' : 'BLOCKED' })}
                              title="Toggle blocked status"
                            >
                              {isBlocked ? 'Unblock' : 'Block'}
                            </button>
                            <button
                              className="btn btn-sm btn-outline-danger"
                              onClick={() => handleDeleteStock(item._id)}
                              title="Delete stock item"
                            >
                              Delete
                            </button>
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default StockManagement;
